import React from "react";
import AllCompo from "../components/AllCompo";
import Footer from "../components/Footer";
import { CartProvider } from "react-use-cart";

function Cart() {
  return (
    <div>
      <AllCompo />
      CartProvider
      <Footer />
    </div>
  );
}

function AllCart() {
  return 
  <CartProvider>
    <Cart />
  </CartProvider>;
}

export default AllCart;
